const modal=document.getElementById('imageModal'),modalImg=document.getElementById('modalImg'),closeBtn=document.querySelector('.close'),galleryImages=document.querySelectorAll('.gallery-img');function openModal(e){e.src&&""!==e.src&&(modal.classList.add('active'),modalImg.src=e.src,modalImg.alt=e.alt,closeBtn&&closeBtn.focus())}galleryImages.forEach(e=>{e.setAttribute("tabindex","0"),e.setAttribute("role","button"),e.getAttribute("aria-label")||e.setAttribute("aria-label",e.alt?`Ampliar imagen: ${e.alt}`:"Ampliar imagen"),e.addEventListener("click",function(){openModal(this)}),e.addEventListener("keydown",function(t){"Enter"!==t.key&&" "!==t.key||(t.preventDefault(),openModal(this))})}),closeBtn&&closeBtn.addEventListener("click",function(){modal.classList.remove("active")}),modal.addEventListener("click",function(e){e.target===modal&&modal.classList.remove("active")}),document.addEventListener("keydown",function(e){"Escape"===e.key&&modal.classList.remove("active")});